package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe load balancers
// with the given name and exports the formatted result to the specified output file.
// It returns the command execution result as a string and any error that occurred.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Build the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Execute the aliyun command and capture its output
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		if exitError, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed with exit code %d: %s", exitError.ExitCode(), string(exitError.Stderr))
		}
		return "", fmt.Errorf("failed to execute aliyun command: %w", err)
	}

	// Build the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set jq's stdin to the aliyun command output using bytes.NewReader
	jqCmd.Stdin = bytes.NewReader(aliyunOutput)

	// Execute jq and capture its output
	jqOutput, err := jqCmd.Output()
	if err != nil {
		if exitError, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("jq command failed with exit code %d: %s", exitError.ExitCode(), string(exitError.Stderr))
		}
		return "", fmt.Errorf("failed to execute jq command: %w", err)
	}

	// Write the jq output to the file
	_, err = file.Write(jqOutput)
	if err != nil {
		return "", fmt.Errorf("failed to write to output file: %w", err)
	}

	// Return the jq output as a string
	return string(jqOutput), nil
}

