package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe load balancers
// with the given name and exports the formatted result to the specified output file.
// It returns the command execution result as a string and any error that occurred.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Create a pipe between aliyun and jq
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun stdout to jq stdin
	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdin pipe: %w", err)
	}

	aliyunOutputPipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stdout pipe: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	jqCmd.Stdout = file
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait() // Clean up aliyun process
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Copy aliyun output to jq input
	go func() {
		defer jqStdin.Close()
		// Read from aliyun and write to jq
		buf := make([]byte, 1024)
		for {
			n, err := aliyunOutputPipe.Read(buf)
			if n > 0 {
				jqStdin.Write(buf[:n])
			}
			if err != nil {
				break
			}
		}
	}()

	// Wait for both commands to complete
	aliyunErr := aliyunCmd.Wait()
	jqErr := jqCmd.Wait()

	// Check for errors
	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %w", aliyunErr)
	}
	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %w", jqErr)
	}

	// Read the content of the output file to return
	outputContent, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(outputContent), nil
}

