package main

import (
	"fmt"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Escape single quotes in the loadBalancerName by replacing them with '\''
	// This ensures that names containing single quotes are handled correctly
	escapedLoadBalancerName := strings.ReplaceAll(loadBalancerName, "'", "'\\''")
	escapedOutputFile := strings.ReplaceAll(outputFile, "'", "'\\''")

	// Construct the shell command
	cmdStr := fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName '%s' | jq '.LoadBalancers.LoadBalancer[]' > '%s'",
		escapedLoadBalancerName, escapedOutputFile)

	cmd := exec.Command("sh", "-c", cmdStr)

	// Capture stdout and stderr
	outputBytes, err := cmd.CombinedOutput()
	outputStr := string(outputBytes)

	if err != nil {
		return outputStr, fmt.Errorf("command failed: %w, output: %s", err, outputStr)
	}

	return outputStr, nil
}

