// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters to prevent path traversal and command injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>&;(){}[]") || strings.ContainsAny(outputFile, "`$\n\r\t|>&;(){}[]") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Validate that outputFile is a valid filename (not a path with directory traversal)
	if strings.Contains(outputFile, "..") {
		return "", fmt.Errorf("output file path contains directory traversal")
	}

	// Validate that outputFile is not empty and doesn't start with a slash (to avoid absolute paths)
	if outputFile == "" || strings.HasPrefix(outputFile, "/") {
		return "", fmt.Errorf("invalid output file path")
	}

	// Execute aliyun command with proper argument escaping
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Get the output from aliyun command
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		if exitError, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(exitError.Stderr))
		}
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Execute jq command with the aliyun output as input
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = strings.NewReader(string(aliyunOutput))

	// Create the output file
	outputFileHandle, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outputFileHandle.Close()

	// Set jq's stdout to the output file
	jqCmd.Stdout = outputFileHandle

	// Capture jq's stderr
	var jqStderr strings.Builder
	jqCmd.Stderr = &jqStderr

	// Run jq command
	err = jqCmd.Run()
	if err != nil {
		return jqStderr.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Return success with empty stdout (since output was redirected to file)
	return "", nil
}

